public int[] noZeroIntegers(int n) {
    for (int a = 1; a < n; ++a) {
        if (Integer.toString(a).indexOf('0') == -1 &&
            Integer.toString(n - a).indexOf('0') == -1) {
            return new int[]{a, n - a};
        }
    }
    return new int[]{0, 0}; // never gets here
}
```

